import React, { useState, useRef, useEffect } from 'react';
import './AIAssistant.css';

const SYSTEM_PROMPT = `You are FreshMart's friendly AI grocery assistant named "Basil" (🌿). You help customers with:
- Recipe suggestions based on ingredients
- Meal planning for the week
- Grocery shopping lists
- Nutritional advice
- Product recommendations from categories: Grains, Dairy, Fruits, Vegetables, Groceries, Bakery, Beverages, Snacks
- Cooking tips and techniques
- Seasonal produce recommendations

Available products in the store:
- Rice 1kg (Grains) - ₹80
- Milk 1L (Dairy) - ₹45
- Sugar 1kg (Groceries) - ₹50
- Apple 1kg (Fruits) - ₹120

Always be friendly, helpful, and concise. Respond in English. When suggesting products, mention their category and approximate price. Use emojis to make responses engaging.`;

const AIAssistant = () => {
  const [messages, setMessages] = useState([
    {
      role: 'assistant',
      content: "Hello! I'm **Basil** 🌿, your FreshMart AI assistant! I can help you with recipes, meal planning, shopping lists, and anything grocery-related. What can I help you with today?",
    },
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef(null);

  const SUGGESTIONS = [
    '🍳 What can I cook with rice and vegetables?',
    '📋 Plan a healthy weekly meal for 2 people',
    '🛒 What should I buy for a South Indian breakfast?',
    '🥗 Suggest high-protein vegetarian meals',
  ];

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = async (text = input) => {
    const trimmed = text.trim();
    if (!trimmed || loading) return;
    setInput('');

    const userMsg = { role: 'user', content: trimmed };
    const updatedMessages = [...messages, userMsg];
    setMessages(updatedMessages);
    setLoading(true);

    try {
      const apiKey = process.env.REACT_APP_CLAUDE_API_KEY;
      if (!apiKey) throw new Error('API key not configured');

      const response = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
        },
        body: JSON.stringify({
          model: 'claude-haiku-4-5-20251001',
          max_tokens: 500,
          system: SYSTEM_PROMPT,
          messages: updatedMessages.map(m => ({ role: m.role, content: m.content })),
        }),
      });

      if (!response.ok) throw new Error('API request failed');
      const data = await response.json();
      const assistantContent = data.content?.[0]?.text || 'Sorry, I could not get a response.';
      setMessages(prev => [...prev, { role: 'assistant', content: assistantContent }]);
    } catch (err) {
      const errMsg = err.message.includes('API key')
        ? 'Please add your REACT_APP_CLAUDE_API_KEY to the .env file to enable AI responses.'
        : 'Sorry, I had trouble connecting. Please try again!';
      setMessages(prev => [...prev, { role: 'assistant', content: errMsg }]);
    } finally {
      setLoading(false);
    }
  };

  const formatMessage = (content) => {
    return content
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\n/g, '<br/>');
  };

  return (
    <div className="ai-page">
      <div className="ai-sidebar">
        <div className="ai-branding">
          <div className="ai-avatar">🌿</div>
          <h2>Basil</h2>
          <p>Your AI Grocery Assistant</p>
        </div>
        <div className="ai-features">
          <h3>I can help with:</h3>
          <ul>
            <li>🍽️ Recipe suggestions</li>
            <li>📅 Meal planning</li>
            <li>🛒 Shopping lists</li>
            <li>🥗 Nutrition advice</li>
            <li>🌱 Seasonal picks</li>
            <li>👨‍🍳 Cooking tips</li>
          </ul>
        </div>
        <div className="env-note">
          <p>💡 Add <code>REACT_APP_CLAUDE_API_KEY</code> to your <code>.env</code> file to activate AI</p>
        </div>
      </div>

      <div className="ai-chat">
        <div className="ai-chat-header">
          <div className="ai-header-info">
            <div className="ai-status-dot"></div>
            <span>Basil is online</span>
          </div>
        </div>

        <div className="ai-messages">
          {messages.map((msg, i) => (
            <div key={i} className={`message ${msg.role}`}>
              {msg.role === 'assistant' && <div className="msg-avatar">🌿</div>}
              <div className="msg-bubble" dangerouslySetInnerHTML={{ __html: formatMessage(msg.content) }} />
              {msg.role === 'user' && <div className="msg-avatar user-av">👤</div>}
            </div>
          ))}
          {loading && (
            <div className="message assistant">
              <div className="msg-avatar">🌿</div>
              <div className="msg-bubble typing-indicator">
                <span></span><span></span><span></span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {messages.length === 1 && (
          <div className="suggestions">
            {SUGGESTIONS.map((s, i) => (
              <button key={i} className="suggestion-chip" onClick={() => sendMessage(s)}>
                {s}
              </button>
            ))}
          </div>
        )}

        <div className="ai-input-area">
          <input
            type="text"
            placeholder="Ask Basil anything about groceries, recipes, meals..."
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && sendMessage()}
            disabled={loading}
          />
          <button className="send-btn" onClick={() => sendMessage()} disabled={loading || !input.trim()}>
            {loading ? '⏳' : '🚀'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIAssistant;
